import { type StravaStatus } from '../../../../services/strava.service.js';
import '../../../status-pill/status-dot/status-dot.component.js';
import type { StatusDot } from '../../../status-pill/status-dot/status-dot.component.js';
import {
    STATUS_EVENTS,
    createStravaSyncEvent,
    createStravaDisconnectEvent,
    createStravaConnectEvent,
} from '../../status-events.js';
import type { StatusEvent } from '../../status-events.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="section">
        <div class="section-header">
            <status-dot id="dot" title="Strava"></status-dot>
            <h3 class="section-title">Connected Services</h3>
        </div>

        <div class="status-grid">
            <span class="status-label">Strava: <span id="strava-badge" class="status-badge"></span></span>
            <span class="status-label">Last Sync: <span id="sync-time"></span></span>
        </div>

        <div class="actions-row">
            <button type="button" class="action-btn action-btn--primary" id="strava-sync" hidden>Sync Strava</button>
            <button type="button" class="action-btn action-btn--danger" id="strava-disconnect" hidden>Disconnect</button>
            <button type="button" class="action-btn action-btn--success" id="strava-connect" hidden>Connect Strava</button>
        </div>
    </div>
`;


export class ServicesSection extends HTMLElement {
    private _stravaStatus: StravaStatus = { connected: false, last_sync: null };

    private dot!: StatusDot;
    private stravaBadge!: HTMLSpanElement;
    private syncTime!: HTMLSpanElement;
    private syncBtn!: HTMLButtonElement;
    private disconnectBtn!: HTMLButtonElement;
    private connectBtn!: HTMLButtonElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.appendChild(template.content.cloneNode(true));

        this.dot = shadow.getElementById('dot') as StatusDot;
        this.stravaBadge = shadow.getElementById('strava-badge') as HTMLSpanElement;
        this.syncTime = shadow.getElementById('sync-time') as HTMLSpanElement;
        this.syncBtn = shadow.getElementById('strava-sync') as HTMLButtonElement;
        this.disconnectBtn = shadow.getElementById('strava-disconnect') as HTMLButtonElement;
        this.connectBtn = shadow.getElementById('strava-connect') as HTMLButtonElement;

        this.syncBtn.addEventListener('click', () => {
            this.syncBtn.disabled = true;
            this.dispatchEvent(createStravaSyncEvent());
        });
        this.disconnectBtn.addEventListener('click', () => {
            this.disconnectBtn.disabled = true;
            this.dispatchEvent(createStravaDisconnectEvent());
        });
        this.connectBtn.addEventListener('click', () => {
            this.connectBtn.disabled = true;
            this.dispatchEvent(createStravaConnectEvent());
        });

        this.render();
    }

    set stravaStatus(val: StravaStatus) {
        if (this._stravaStatus.connected === val.connected && this._stravaStatus.last_sync === val.last_sync) return;
        this._stravaStatus = val;
        this.render();
    }

    private formatRelativeTime(isoDate: string | null): string {
        if (!isoDate) return 'Never';
        const diff = Temporal.Now.instant().epochMilliseconds - Temporal.Instant.from(isoDate).epochMilliseconds;
        const minutes = Math.floor(diff / 60_000);
        if (minutes < 1) return 'just now';
        if (minutes < 60) return `${minutes}m ago`;
        const hours = Math.floor(minutes / 60);
        if (hours < 24) return `${hours}h ago`;
        const days = Math.floor(hours / 24);
        return `${days}d ago`;
    }

    static getStatus(connected: boolean) {
        return {
            color: connected ? 'green' : 'gray'
        };
    }

    private render() {
        const { connected, last_sync } = this._stravaStatus;
        const pillStatus = ServicesSection.getStatus(connected);

        this.dot.setAttribute('color', pillStatus.color);
        
        this.stravaBadge.textContent = connected ? 'Connected' : 'Disconnected';
        this.stravaBadge.className = `status-badge ${connected ? 'status-badge--active' : 'status-badge--inactive'}`;
        
        this.syncTime.textContent = this.formatRelativeTime(last_sync);

        this.syncBtn.hidden = !connected;
        this.disconnectBtn.hidden = !connected;
        this.connectBtn.hidden = connected;

        this.syncBtn.disabled = false;
        this.disconnectBtn.disabled = false;
        this.connectBtn.disabled = false;
    }
}

customElements.define('services-status-section', ServicesSection);
